{
"title": "संदर्भ विंडो मूल बातें",
  "group": "बुनियादें",
  "options": [
    {
      "text": "प्रति मिनट अधिकतम अनुरोधों की संख्या"
    },
    {
      "text": "इनपुट और आउटपुट के लिए संयुक्त टोकन सीमा"
    },
    {
      "text": "संवाद में संदेशों की संख्या"
    },
    {
      "text": "सत्रों के बीच उपलब्ध मेमोरी"
    }
  ],
  "questionProse": [
    "LLM में \"संदर्भ विंडो\" किसे दर्शाता है?"
  ],
  "explanationProse": [
    "संदर्भ विंडो वह कुल टोकन संख्या है जो मॉडल एकल कॉल में प्रोसेस कर सकता है — **इनपुट + आउटपुट संयुक्त**। 128K संदर्भ विंडो का मतलब है कि आपका प्रॉम्प्ट + प्राप्त दस्तावेज़ + संवाद इतिहास + मॉडल की प्रतिक्रिया सभी को 128,000 टोकन के भीतर फिट होना चाहिए।\n\n    इसका सत्रों, मेमोरी, या रेट लिमिट से कोई लेना‑देना नहीं है। जब आप सीमा तक पहुँचते हैं, तो मॉडल या तो ट्रंकेट करता है, त्रुटि देता है, या — बदतर — चुपचाप उन टोकनों को हटा देता है जो आप नहीं चाहते थे।"
  ]
}
